/* ------------------------------------------------------------------ */
/* LOGIC                                                               */
/* ------------------------------------------------------------------ */

function pool(catKey, level, equipment, excludeName) {
  return EXERCISES[catKey].filter(
    (e) =>
      e.lvl <= LEVELS[level] &&
      e.eq.every((q) => equipment.includes(q)) &&
      e.name !== excludeName
  );
}

function pick(list) {
  if (!list.length) return null;
  return list[Math.floor(Math.random() * list.length)];
}

function pickLeveled(list, level) {
  if (!list.length) return null;
  const L = LEVELS[level];
  const weighted = [];
  for (const ex of list) {
    const w = ex.lvl === L ? 3 : ex.lvl === L - 1 ? 2 : 1;
    for (let k = 0; k < w; k++) weighted.push(ex);
  }
  return weighted[Math.floor(Math.random() * weighted.length)];
}

function template(focus, level, includeUpper) {
  let slots;
  if (focus === "reactive") {
    slots = ["pogo", "multi", "bounding"];
    if (level === "advanced") slots.push("depth");
  } else if (focus === "power") {
    slots = ["inplace", "standing"];
    if (level !== "beginner") slots.push("depth");
    else slots.push("multi");
  } else {
    slots = ["pogo", Math.random() < 0.5 ? "standing" : "inplace", Math.random() < 0.5 ? "multi" : "bounding"];
  }
  if (includeUpper) slots.push("upper");
  return slots;
}

function buildSession(slots, level, equipment) {
  const fastCap = FAST_CAPS[level];
  const budget = BUDGETS[level];
  const minLevel = LEVELS[level];
  const fastOf = (p) => p.reduce((s, { cat, ex }) => s + (cat !== "upper" && ex.fast ? ex.sets * ex.reps : 0), 0);
  const loadOf = (p) => p.reduce((s, { cat, ex }) => s + (cat !== "upper" ? ex.sets * ex.reps : 0), 0);
  // Pick the highest-load valid template combination from 80 attempts, only from target-level or higher exercises
  let best = null, underCap = null, fallback = null;
  for (let attempt = 0; attempt < 80; attempt++) {
    const picked = slots
      .map((cat) => {
        const challenging = pool(cat, level, equipment).filter((ex) => ex.lvl >= minLevel);
        const ex = pickLeveled(challenging, level);
        return ex ? { cat, ex } : null;
      })
      .filter(Boolean);
    const f = fastOf(picked);
    if (f <= fastCap) {
      if (loadOf(picked) <= budget) {
        if (!best || loadOf(picked) > loadOf(best)) best = picked;
      }
      if (!underCap) underCap = picked;
    }
    if (!fallback || f < fastOf(fallback)) fallback = picked;
  }
  const session = best || underCap || fallback;

  return session;
}

const Die = () => (
  <span className="pd-die" style={{ backgroundImage: `url(${DIE_IMG})` }} aria-hidden="true" />
);



